$(function() {
    const body = $("body");
    
    // Verifica se tem localStorage, se sim direciona para a página inicial
    if (localStorage.getItem("access_token") && localStorage.getItem("refresh_token")) {
        window.location.href = PAGINA_INICIAL;
    }
    
    const $form_email = $("#form-email");
    const $form_senha = $("#form-senha");
    const $email = $("#email");
    const $senha = $("#senha");
    const $form_alerta = $("#form-alerta");
    const $form_button = $('#form-button');
    
    let regexEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    
    $email.keydown(function(e) {
        if (e.key === "Enter") {
            $form_button.click();
        }
    });
    $senha.keydown(function(e) {
        if (e.key === "Enter") {
            $form_button.click();
        }
    });

    $email.blur(function() {
        if (!regexEmail.test($email.val())) {
            $form_email.removeClass("form-certo").addClass("form-erros");
        }
        else {
            $form_email.removeClass("form-erros").addClass("form-certo");
        }
    });
    $senha.blur(function() {
        if ($senha.val().length == 0) {
            $form_senha.removeClass("form-certo").addClass("form-erros");
        }
        else {
            $form_senha.removeClass("form-erros").addClass("form-certo");
        }
    });

    $('#form-button').on('click', function () {
        let mensagemErro = "";
        let erros = false;

        const email = $email.val();
        const senha = $senha.val();
        
        if (email.length == 0 || senha.length == 0) {
            mensagemErro = "Existem campos em branco";
            erros = true;
        }
        
        // valida email
        if (!regexEmail.test(email)) {
            mensagemErro = "E-mail inválido";
            erros = true;
            $form_email.removeClass("form-certo").addClass("form-erros");
        }
        else {
            $form_email.removeClass("form-erros").addClass("form-certo");
        }
        
        if (erros) {
            $form_alerta.text(mensagemErro).addClass("form-alerta-erros").removeClass("form-alerta-aviso form-alerta-certo display-none");
        }
        else {
            body.addClass("loading");
            $form_alerta.addClass("display-none");
            
            $.ajax({
                url: URL_REQUESTS + '5000/login',
                method: "POST",
                contentType: "application/json",
                data: JSON.stringify({ email: email, password: senha }),
                success: function(res) {
                    $form_alerta.text("Login realizado com sucesso").addClass("form-alerta-certo").removeClass("form-alerta-aviso form-alerta-erros display-none");
                    localStorage.setItem("access_token", res.access_token);
                    localStorage.setItem("refresh_token", res.refresh_token);
                    localStorage.setItem("admin", res.admin);
                    localStorage.setItem("email", res.email);
                    localStorage.setItem("nome", res.nome);
                    localStorage.setItem("status", JSON.stringify(res.status));
                    localStorage.setItem("pdvs", JSON.stringify(res.pdvs));
                    localStorage.setItem("pdv_selecionado", res.pdvs.length ? JSON.stringify(res.pdvs[0]) : null);
                    
                    window.location.href = PAGINA_INICIAL;
                    body.removeClass("loading");
                },
                error: function(res) {
                    body.removeClass("loading");
                    $form_alerta.text(res.responseJSON.error).addClass("form-alerta-erros").removeClass("form-alerta-aviso form-alerta-certo display-none");
                }
            });
        }
    });
});